import{_ as a,o as e,c as r,ag as l}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"プレビューと用紙設定","description":"","frontmatter":{},"headers":[],"relativePath":"guide/preview-settings.md","filePath":"guide/preview-settings.md"}'),i={name:"guide/preview-settings.md"};function d(o,t,n,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="プレビューと用紙設定" tabindex="-1">プレビューと用紙設定 <a class="header-anchor" href="#プレビューと用紙設定" aria-label="Permalink to &quot;プレビューと用紙設定&quot;">​</a></h1><p>Excel をアップロードすると、帳票のプレビュー画面が表示されます。ここでは用紙サイズや表示方法を確認・調整できます。</p><hr><h2 id="プレビュー画面の構成" tabindex="-1">プレビュー画面の構成 <a class="header-anchor" href="#プレビュー画面の構成" aria-label="Permalink to &quot;プレビュー画面の構成&quot;">​</a></h2><p>プレビュー画面には以下の要素があります:</p><ul><li><strong>用紙設定バー</strong> — 用紙サイズ・印刷方向の選択</li><li><strong>プレビューエリア</strong> — PDF 表示またはテーブル表示</li><li><strong>シートタブ</strong> — 複数シートがある場合のタブ切替</li><li><strong>セル情報</strong> — 検出されたセル数の表示</li></ul><hr><h2 id="用紙サイズ" tabindex="-1">用紙サイズ <a class="header-anchor" href="#用紙サイズ" aria-label="Permalink to &quot;用紙サイズ&quot;">​</a></h2><p>帳票の用紙サイズを選択します。AI 解析時のクラスター座標計算に影響します。</p><table tabindex="0"><thead><tr><th>サイズ</th><th>寸法 (mm)</th><th>用途</th></tr></thead><tbody><tr><td><strong>A4</strong></td><td>210 × 297</td><td>一般的な帳票（デフォルト）</td></tr><tr><td><strong>A3</strong></td><td>297 × 420</td><td>大判の帳票・点検表</td></tr><tr><td><strong>B4</strong></td><td>257 × 364</td><td>B4 サイズの帳票</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">用紙サイズは AI 解析前に設定</p><p>用紙サイズは AI 解析のクラスター座標に影響します。解析前に正しいサイズを選んでください。</p></div><hr><h2 id="印刷方向" tabindex="-1">印刷方向 <a class="header-anchor" href="#印刷方向" aria-label="Permalink to &quot;印刷方向&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方向</th><th>説明</th></tr></thead><tbody><tr><td><strong>縦 (Portrait)</strong></td><td>通常の縦向き</td></tr><tr><td><strong>横 (Landscape)</strong></td><td>横向き</td></tr></tbody></table><p>実際の Excel 帳票の印刷設定に合わせて選択してください。</p><hr><h2 id="表示モード" tabindex="-1">表示モード <a class="header-anchor" href="#表示モード" aria-label="Permalink to &quot;表示モード&quot;">​</a></h2><h3 id="pdf-プレビュー" tabindex="-1">PDF プレビュー <a class="header-anchor" href="#pdf-プレビュー" aria-label="Permalink to &quot;PDF プレビュー&quot;">​</a></h3><p>Excel から変換された PDF が表示されます。実際の帳票レイアウトに近い表示です。</p><ul><li>クラスターエディタでは、この PDF 上にクラスターがオーバーレイ表示されます</li><li>複数ページの場合はページ送りが表示されます</li></ul><h3 id="テーブルプレビュー" tabindex="-1">テーブルプレビュー <a class="header-anchor" href="#テーブルプレビュー" aria-label="Permalink to &quot;テーブルプレビュー&quot;">​</a></h3><p>PDF が利用できない場合、Excel のセルデータがテーブル形式で表示されます。</p><ul><li>セルの値、結合状態が確認できます</li><li>スタイル情報（色、フォント等）も反映されます</li></ul><hr><h2 id="シートの切替" tabindex="-1">シートの切替 <a class="header-anchor" href="#シートの切替" aria-label="Permalink to &quot;シートの切替&quot;">​</a></h2><p>複数シートがある Excel の場合、プレビュー下部にシートタブが表示されます。</p><ul><li>タブをクリックしてシートを切り替えます</li><li>AI 解析は選択中のシートに対して実行されます</li></ul><hr><h2 id="次のステップ" tabindex="-1">次のステップ <a class="header-anchor" href="#次のステップ" aria-label="Permalink to &quot;次のステップ&quot;">​</a></h2><p>プレビューの確認が終わったら「AI で解析する」ボタンを押して、<a href="./basic-flow.html#step-3-ai-解析">AI 解析</a> に進みます。</p>',30)])])}const b=a(i,[["render",d]]);export{u as __pageData,b as default};
